'use client';

import { jsPDF } from 'jspdf';
import { useState } from 'react';
import { useTranslations } from 'next-intl';
import { useAuth } from '@/context/AuthContext';

import { ClientDAO } from '@/types/Api';
import { createPayment } from '@/lib/api-sales';
import Select from '@/components/atoms/select';
import { crearFacturaVenta } from '@/lib/api-saleInvoce';
import { SaleItem, SaleItemForAPI } from '@/types/Api';
import SearchBarUniversal from '@/components/molecules/SearchBar';
import { ToggleSwitch } from '@/components/molecules/ToggleSwitch';
import { useBalance } from '@/context/BalanceContext';

interface InvoiceModalProps {
  subtotal: number;
  taxTotal: number;
  total: number;
  items: SaleItem[];
  onSuccess: () => void;
  onCancel: () => void;
  handleSuccessSale: () => void;
}

export default function InvoiceModal({
  subtotal,
  taxTotal,
  total,
  items,
  handleSuccessSale,
  onSuccess,
  onCancel
}: InvoiceModalProps) {
  const t = useTranslations("invoiceModal");

  const { balance, setBalance } = useBalance();
  const { user } = useAuth();
  const [selectedClient, setSelectedClient] = useState<ClientDAO | null>(null);
  const [isElectronicBill, setIsElectronicBill] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState('CASH');
  const [pdfUrl, setPdfUrl] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  const formatCurrency = (value: number) => {
    return value.toLocaleString('es-CO', { style: 'currency', currency: 'COP', minimumFractionDigits: 0 });
  };

  const generatePDF = async() => {
    if (!selectedClient) return;
    
    // Configuración para impresora térmica (80mm de ancho)
    const doc = new jsPDF({
      orientation: 'portrait',
      unit: 'mm',
      format: [80, (items.length*12)+120], 
    });

    let yPosition = 8;
    const pageWidth = 80;
    const margin = 4;
    const contentWidth = pageWidth - (margin * 2);

    // Función auxiliar para centrar texto
    const centerText = (text: string, y: number, fontSize: number = 10) => {
      doc.setFontSize(fontSize);
      const textWidth = doc.getTextWidth(text);
      doc.text(text, (pageWidth - textWidth) / 2, y);
    };

    // Función auxiliar para texto alineado a la derecha
    const rightAlignText = (text: string, y: number, fontSize: number = 9) => {
      doc.setFontSize(fontSize);
      const textWidth = doc.getTextWidth(text);
      doc.text(text, pageWidth - margin - textWidth, y);
    };

    const logoBase64 = "data:image/png;base64, ";

    doc.addImage(logoBase64, 'PNG', (pageWidth/2)-8, yPosition, 15, 10);

    // Nombre de la empresa centrado y destacado
    doc.setFont('helvetica', 'bold');
    centerText(user?.name || t('pdf.companyName'), yPosition+=17, 12);
    yPosition += 6;

    // Información de la empresa centrada
    doc.setFont('helvetica', 'normal');
    const companyInfo = [
      'NIT: 900785552-1',
      'Carrera 5 Calle 3',
      'Tel: 3178582593'
    ];

    doc.setFontSize(8);
    companyInfo.forEach(info => {
      centerText(info, yPosition, 8);
      yPosition += 3.5;
    });

    // Línea separadora elegante
    yPosition += 2;
    doc.setLineWidth(0.5);
    doc.setDrawColor(66, 139, 202); // Color azul
    doc.line(margin, yPosition, pageWidth - margin, yPosition);
    yPosition += 4;

    // Título del documento centrado y destacado
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(66, 139, 202); // Color azul
    centerText(t('pdf.title'), yPosition, 11);
    doc.setTextColor(0, 0, 0); // Volver a negro
    yPosition += 8;

    // Información del cliente en caja elegante
    doc.setDrawColor(200, 200, 200);
    doc.setLineWidth(0.3);
    doc.rect(margin, yPosition - 2, contentWidth, 16, 'S');
    
    yPosition += 2;
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(9);
    doc.text('CLIENTE:', margin + 2, yPosition);
    yPosition += 4;
    
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);
    const clientName = `${selectedClient.firstName} ${selectedClient.lastName}`;
    const clientLines = doc.splitTextToSize(clientName, contentWidth - 4);
    doc.text(clientLines, margin + 2, yPosition);
    yPosition += clientLines.length * 3 + 2;

    // Fecha 
    doc.setFontSize(8);
    doc.text(`Fecha: ${new Date().toLocaleDateString('es-CO')}`, margin + 2, yPosition);
    yPosition += 3.5;

    // Línea separadora para productos
    doc.setDrawColor(66, 139, 202);
    doc.line(margin, yPosition, pageWidth - margin, yPosition);
    yPosition += 4;

    // Encabezado de productos centrado
    doc.setFont('helvetica', 'bold');
    centerText('PRODUCTOS', yPosition, 9);
    yPosition += 6;

    // Lista de productos optimizada para impresora térmica
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);

    items.forEach((item, index) => {
      // Línea separadora ligera entre productos
      if (index > 0) {
        doc.setDrawColor(230, 230, 230);
        doc.setLineWidth(0.1);
        doc.line(margin + 5, yPosition - 1, pageWidth - margin - 5, yPosition - 1);
      }

      // Nombre del producto destacado
      doc.setFont('helvetica', 'bold');
      const productName = item.name || 'Producto';
      const nameLines = doc.splitTextToSize(productName, contentWidth - 2);
      doc.text(nameLines, margin + 1, yPosition);
      yPosition += nameLines.length * 3 + 1;

      // Detalles del producto en formato limpio
      doc.setFont('helvetica', 'normal');
      const quantity = item.quantity.toString();
      const unitPrice = formatCurrency(item.basePrice || item.price);
      const totalPrice = formatCurrency(item.quantity * item.price);

      // Cantidad y precio unitario
      doc.text(`${quantity} x ${unitPrice}`, margin + 3, yPosition);
      yPosition += 3;

      // Total del item alineado a la derecha
      rightAlignText(totalPrice, yPosition - 3, 8);

      yPosition += 3;
    });

    // Línea separadora para totales
    yPosition += 2;
    doc.setDrawColor(66, 139, 202);
    doc.setLineWidth(0.8);
    doc.line(margin, yPosition, pageWidth - margin, yPosition);
    yPosition += 5;

    // Resumen de totales con mejor formato
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(9);

    // Subtotal
    doc.text('Subtotal:', margin, yPosition);
    rightAlignText(formatCurrency(subtotal), yPosition, 9);
    yPosition += 4;

    // Total destacado con fondo
    doc.setFont('helvetica', 'bold');
    doc.setFillColor(66, 139, 202);
    doc.rect(margin, yPosition - 3, contentWidth, 8, 'F');
    
    doc.setTextColor(255, 255, 255); // Texto blanco
    doc.setFontSize(11);
    doc.text('TOTAL:', margin + 2, yPosition + 2);
    
    const totalText = formatCurrency(total);
    const totalWidth = doc.getTextWidth(totalText);
    doc.text(totalText, pageWidth - margin - totalWidth - 2, yPosition + 2);
    
    doc.setTextColor(0, 0, 0); // Volver a negro
    yPosition += 12;

    // Línea final
    doc.setDrawColor(66, 139, 202);
    doc.setLineWidth(0.5);
    doc.line(margin, yPosition, pageWidth - margin, yPosition);
    yPosition += 6;

    // Mensaje de agradecimiento centrado
    doc.setFont('helvetica', 'italic');
    doc.setFontSize(9);
    centerText('¡Gracias por su venta!', yPosition, 9);
    yPosition += 5;

    const pdfBlob = doc.output('blob');
    const url = URL.createObjectURL(pdfBlob);
    setPdfUrl(url);
  };

  const handleProcessSale = async () => {
    console.log('Processing sale for client:', selectedClient);
    if (!selectedClient) {
      setError(t('errors.noClient'));
      return;
    }

    if (!user) {
      setError(t('errors.auth'));
      return;
    }
    
    setIsLoading(true);
    setError('');
    
    try {
      const productsForAPI: SaleItemForAPI[] = items.map(item => ({
        tenantId: user?.tenantId || '', 
        productId: item.productId || '',
        quantity: item.quantity,
        unitPrice: item.price,
        announcementId: null
      }));

      const invoiceResponse = await crearFacturaVenta({
        clientId: selectedClient.id,
        totalPrice: total,
        tenantId: user.tenantId,
        electronicBill: isElectronicBill,
        products: productsForAPI
      });
      
      await createPayment({
        tenantId: user.tenantId,
        amount: total,
        paymentMethod: paymentMethod,
        reference: `PAY-${Date.now()}`,
        invoiceId: invoiceResponse.id
      });

      if(balance !== null)
        setBalance(balance - total);

      generatePDF();
      
    } catch (error) {
      console.error('Error processing sale:', error);
      setError(error instanceof Error ? error.message : t('errors.sale'));
    } finally {
      setIsLoading(false);
    }
  };

  const handleDownloadAndClose = () => {
    onSuccess();
  };

  return (
    <div className="p-4">
      <h2 className="text-lg font-semibold mb-4 text-white">{t('title')}</h2>
      
      <div className="mb-4">
        <label className="block text-sm font-medium mb-1 text-white">{t('client')}</label>
        <SearchBarUniversal
          searchType="clients"
          onAddToCart={(item) => setSelectedClient(item as ClientDAO)} 
          showResults={true}
          placeholder={t('clientPlaceholder')}
        />
      </div>
      
      <div className="mb-4">
        <label className="block text-sm font-medium mb-1 text-white">{t('payment')}</label>
        <Select
          value={paymentMethod}
          onChange={(e: any) => setPaymentMethod(e.target.value)}
          className="w-full p-2 border rounded"
          options={[
            { value: "CASH", label: t("paymentMethods.CASH") },
            { value: "CARD", label: t("paymentMethods.CARD") },
            { value: "TRANSFER", label: t("paymentMethods.TRANSFER") }
          ]}
          placeholder={t('paymentPlaceholder')}
        />
      </div>
      
      <div className="mb-4">
        <div className="flex items-center justify-between">
          <span className='text-white'>{t('electronicBill')}</span>
          <ToggleSwitch
            options={[t('toggle.no'), t('toggle.yes')]}
            activeIndex={isElectronicBill ? 1 : 0} 
            onChange={(index) => setIsElectronicBill(index === 1)} 
          />
        </div>
      </div>
      
      <div className="space-y-2 my-4">
        <div className="flex justify-between">
          <span className='text-white'>{t('labels.subtotal')}:</span>
          <span className='text-white'>{formatCurrency(subtotal)}</span>
        </div>
        <div className="flex justify-between">
          <span className='text-white'>{t('labels.tax')}:</span>
          <span className='text-white'>{formatCurrency(taxTotal)}</span>
        </div>
        <div className="flex justify-between font-bold">
          <span className='text-white'>Total:</span>
          <span className='text-white'>{formatCurrency(total)}</span>
        </div>
      </div>
      
      {error && (
        <div className="text-red-500 mb-4">{error}</div>
      )}

      {pdfUrl ? (
        <div className="mt-6">
          <h3 className="text-lg font-medium mb-3 text-white">{t('preview.title')}</h3>
          <iframe
            src={pdfUrl}
            width="100%"
            height="500px"
            title="Vista previa de la factura"
            className="border border-gray-300 mb-4"
          />
          <div className="flex justify-end space-x-4 mt-6">
            <button
              onClick={handleDownloadAndClose}
              className="px-4 py-2 text-white border border-gray-300 rounded hover:bg-gray-100 hover:text-black"
              disabled={isLoading}
            >
              {t('preview.finish')}
            </button>
            <a
              href={pdfUrl}
              download={`factura_${new Date().toISOString().split('T')[0]}.pdf`}
              className="px-4 py-2 bg-green-600 text-white rounded hover:bg-green-700"
              onClick={handleDownloadAndClose}
            >
              {t('preview.download')}
            </a>
          </div>
        </div>
      ) : (
        <div className="flex justify-end space-x-4 mt-6">
          <button
            onClick={onCancel}
            className="px-4 py-2 border border-gray-300 rounded text-white hover:bg-gray-100 hover:text-black"
            disabled={isLoading}
          >
            {t('cancel')}
          </button>
          <button
            onClick={handleProcessSale}
            className="px-4 py-2 bg-green-600 text-white rounded hover:bg-green-700 disabled:bg-gray-400"
            disabled={isLoading || !selectedClient}
          >
            {isLoading ? t('processing') : t('submit')}
          </button>
        </div>
      )}
    </div>
  );
}